"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["93103"],{67967(t){t.exports=JSON.parse('{"tag":{"label":"standard","permalink":"/sysanalyst-kb.github.io/tech/tags/standard","allTagsPath":"/sysanalyst-kb.github.io/tech/tags","count":5,"items":[{"id":"dicom","title":"DICOM \u2014 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0445 \u0438\u0437\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0439","description":"DICOM (Digital Imaging and Communications in Medicine) \u2014 \u043C\u0435\u0436\u0434\u0443\u043D\u0430\u0440\u043E\u0434\u043D\u044B\u0439 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u0434\u043B\u044F \u043F\u0435\u0440\u0435\u0434\u0430\u0447\u0438, \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0438 \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0445 \u0438\u0437\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0439. \u041E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442: \u0444\u043E\u0440\u043C\u0430\u0442 \u0444\u0430\u0439\u043B\u0430 (\u0441\u043D\u0438\u043C\u043A\u0438 + \u043C\u0435\u0442\u0430\u0434\u0430\u043D\u043D\u044B\u0435 \u0432 \u0442\u0435\u0433\u0430\u0445), \u0441\u0435\u0442\u0435\u0432\u044B\u0435 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B\u044B (Store, Query/Retrieve, Worklist), \u0441\u0436\u0430\u0442\u0438\u0435 \u0438 \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0432\u043E \u0432\u0441\u0435\u0445 PACS-\u0441\u0438\u0441\u0442\u0435\u043C\u0430\u0445. \u0412 \u043C\u0438\u0440\u0435 > 1 \u043C\u043B\u0440\u0434 DICOM-\u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0439 (2024). \u041A\u043B\u044E\u0447\u0435\u0432\u043E\u0439 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u0434\u043B\u044F \u0440\u0430\u0434\u0438\u043E\u043B\u043E\u0433\u0438\u0438, \u043C\u0430\u043C\u043C\u043E\u0433\u0440\u0430\u0444\u0438\u0438, \u0423\u0417\u0418.","permalink":"/sysanalyst-kb.github.io/tech/dicom"},{"id":"edi","title":"EDI \u2014 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u044B\u0439 \u043E\u0431\u043C\u0435\u043D \u0434\u0430\u043D\u043D\u044B\u043C\u0438","description":"EDI (Electronic Data Interchange) \u2014 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0433\u043E \u043E\u0431\u043C\u0435\u043D\u0430 \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u043C\u0438 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u0430\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0430\u043C\u0438 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0446\u0435\u043F\u043E\u0447\u043A\u0438 (\u043F\u043E\u0441\u0442\u0430\u0432\u0449\u0438\u043A \u2194 \u0440\u0438\u0442\u0435\u0439\u043B\u0435\u0440 \u2194 \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u0447\u0438\u043A \u2194 \u043C\u0430\u0440\u043A\u0435\u0442\u043F\u043B\u0435\u0439\u0441). \u0412 \u0420\u0424 EDI-\u043E\u0431\u043E\u0440\u043E\u0442 \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u0435\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u043E\u0432\u0430\u0439\u0434\u0435\u0440\u043E\u0432 (\u0414\u0438\u0430\u0434\u043E\u043A, \u0421\u0411\u0418\u0421, 1\u0421-\u042D\u0414\u041E, \u041A\u043E\u0440\u0443\u0441) \u0438 \u0444\u043E\u0440\u043C\u0430\u0442\u044B ORDERS (\u0437\u0430\u043A\u0430\u0437 \u043D\u0430 \u043F\u043E\u0441\u0442\u0430\u0432\u043A\u0443), DESADV (\u0443\u0432\u0435\u0434\u043E\u043C\u043B\u0435\u043D\u0438\u0435 \u043E\u0431 \u043E\u0442\u0433\u0440\u0443\u0437\u043A\u0435), RECADV (\u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435 \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F), INVOIC (\u0441\u0447\u0451\u0442-\u0444\u0430\u043A\u0442\u0443\u0440\u0430). EDI \u0441\u043D\u0438\u0436\u0430\u0435\u0442 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0438\u0437\u0434\u0435\u0440\u0436\u043A\u0438 \u043D\u0430 30-50% \u043F\u043E \u0441\u0440\u0430\u0432\u043D\u0435\u043D\u0438\u044E \u0441 \u0431\u0443\u043C\u0430\u0436\u043D\u044B\u043C \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442\u043E\u043C. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u043A\u0430\u0440\u0442\u044B \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 (mapping) \u043C\u0435\u0436\u0434\u0443 \u0444\u043E\u0440\u043C\u0430\u0442\u0430\u043C\u0438 \u0438 \u043D\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442 \u0441\u0442\u0430\u0442\u0443\u0441\u043D\u0443\u044E \u043C\u043E\u0434\u0435\u043B\u044C \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u0432.","permalink":"/sysanalyst-kb.github.io/tech/edi"},{"id":"hl7","title":"HL7 FHIR \u2014 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u043E\u0433\u043E \u043E\u0431\u043C\u0435\u043D\u0430 \u0434\u0430\u043D\u043D\u044B\u043C\u0438","description":"HL7 FHIR (Fast Healthcare Interoperability Resources) \u2014 \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0439 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u043E\u0431\u043C\u0435\u043D\u0430 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u043C\u0438 \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u043D\u0430 REST API (JSON/XML). \u0412\u044B\u0442\u0435\u0441\u043D\u044F\u0435\u0442 HL7 v2 (\u0442\u0435\u043A\u0441\u0442\u043E\u0432\u044B\u0435 MLLP-\u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u044F). \u0420\u0435\u0441\u0443\u0440\u0441\u044B \u0415\u041C\u0418\u0410\u0421 \u041C\u043E\u0441\u043A\u0432\u044B, \u0440\u0435\u0433\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u0415\u0413\u0418\u0421\u0417, \u0441\u0435\u0442\u0438 \u0447\u0430\u0441\u0442\u043D\u044B\u0445 \u043A\u043B\u0438\u043D\u0438\u043A.","permalink":"/sysanalyst-kb.github.io/tech/hl7"},{"id":"iso20022","title":"ISO 20022 \u2014 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u0435 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u044F","description":"ISO 20022 \u2014 \u043C\u0435\u0436\u0434\u0443\u043D\u0430\u0440\u043E\u0434\u043D\u044B\u0439 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u0434\u043B\u044F \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0433\u043E \u043E\u0431\u043C\u0435\u043D\u0430 \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u043C\u0438 \u0438\u043D\u0441\u0442\u0438\u0442\u0443\u0442\u0430\u043C\u0438. \u0417\u0430\u043C\u0435\u043D\u044F\u0435\u0442 \u0441\u0442\u0430\u0440\u044B\u0435 \u0444\u043E\u0440\u043C\u0430\u0442\u044B (MT \u2014 \u0432 SWIFT, UFE/STM \u2014 \u0432 \u043D\u0430\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0445 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u0445).","permalink":"/sysanalyst-kb.github.io/tech/iso20022"},{"id":"tmforum","title":"TM Forum Open API \u2014 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 Telecom","description":"TM Forum \u2014 \u0433\u043B\u043E\u0431\u0430\u043B\u044C\u043D\u0430\u044F \u0430\u0441\u0441\u043E\u0446\u0438\u0430\u0446\u0438\u044F, \u0440\u0430\u0437\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u044E\u0449\u0430\u044F \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442\u044B \u0434\u043B\u044F Telecom-\u0438\u043D\u0434\u0443\u0441\u0442\u0440\u0438\u0438.","permalink":"/sysanalyst-kb.github.io/tech/tmforum"}],"unlisted":false}}')}}]);